// writeNewFile (init.ts L273-279)
function writeNewFile(path: string, content: string): void {
  if (existsSync(path)) {
    throw new Error(`ABORT: ${path} already exists. fab init is non-destructive.`);
  }
  writeFileSync(path, content, 'utf8');
}

// copyTemplateIfMissing (init.ts L281-289) — skip-not-abort pattern
function copyTemplateIfMissing(templatePath: string, targetPath: string): 'created' | 'skipped' {
  mkdirSync(dirname(targetPath), { recursive: true });
  if (existsSync(targetPath)) return 'skipped';
  copyFileSync(templatePath, targetPath);
  return 'created';
}

file_write_skip_abort.force_injection_pattern:
// With --force: delete blocking files before calling initFabric, OR
// pass force flag through and change guards:
if (existsSync(forensicPath) && !args.force) {
  throw new Error(`ABORT: ${forensicPath} already exists. fab init is non-destructive.`);
}
if (args.force && existsSync(fabricDir)) {
  rmSync(fabricDir, { recursive: true });
}
if (args.force && existsSync(agentsPath)) {
  rmSync(agentsPath);
}

