// vitest.config.ts: environment + alias
export default defineConfig({
  resolve: { alias: { '@fenglimg/fabric-shared': resolve(packageRoot, '../shared/src/index.ts') } },
  test: { environment: 'node', include: ['__tests__/**/*.test.ts'] },
});

// Test file structure:
import { afterEach, describe, expect, it } from 'vitest';
import { initFabric } from '../src/commands/init.ts';
import { cleanupFixtureRoot, createWerewolfFixtureRoot, writeFixtureFile } from './helpers/init-test-utils.ts';

const tempRoots: string[] = [];
aftterEach(() => { while (tempRoots.length > 0) cleanupFixtureRoot(tempRoots.pop()!); });

describe('initFabric --force behavior', () => {
  it('overwrites existing AGENTS.md when --force is passed', () => {
    const target = createWerewolfFixtureRoot('fab-init-force');
    tempRoots.push(target);
    writeFixtureFile(target, 'AGENTS.md', '# old\n');

    // Test direct handler call (not CLI spawn)
    expect(() => initFabric(target, { force: true })).not.toThrow();
    expect(readFixtureFile(target, 'AGENTS.md')).not.toBe('# old\n');
  });
});

// createWerewolfFixtureRoot copies examples/werewolf-minigame-stub to /tmp,
// strips AGENTS.md and .fabric so init has a clean slate.

